framework_css:
/*
  Global design system
  Derived from provided palette and screenshot
*/

:root {
  /* Brand colors */
  --color-primary-600: #8AA883; /* soft leaf green */
  --color-primary-400: #B7C7A0; /* light sage */

  --color-secondary-600: #7A9A9A; /* muted blue-green, nav links */
  --color-secondary-400: #C8B58A; /* warm beige accent */

  --color-accent: #7A9A9A;

  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F5FAF7; /* page background */
  --color-neutral-800: #4B5A52; /* primary text */

  --color-border-subtle: #DCE4DD;

  --color-success: #7EA28D;
  --color-error: #C96B6B;
  --color-warning: #E0A85C;
  --color-info: #5C8F8B;

  /* Typography */
  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "Source Sans 3", "Helvetica Neue", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  /* Layout */
  --content-width: 1100px;
}

/* CSS reset-ish foundation */

*, *::before, *::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body.site {
  margin: 0;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-050);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-secondary-600);
  text-decoration: none;
}

a:hover,
a:focus {
  color: var(--color-neutral-800);
  text-decoration: underline;
}

p {
  margin-top: 0;
  margin-bottom: var(--space-sm);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-800);
  margin-top: 0;
  margin-bottom: var(--space-sm);
  line-height: var(--line-height-tight);
}

h1 {
  font-size: var(--font-size-h1);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

small {
  font-size: var(--font-size-small);
}

.container {
  max-width: var(--content-width);
  margin: 0 auto;
  padding-left: var(--space-lg);
  padding-right: var(--space-lg);
}

.site-main {
  flex: 1 0 auto;
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xl);
}

/* Header styling matching design */

.site-header {
  background-color: var(--color-neutral-000);
  border-bottom: 1px solid rgba(220, 228, 221, 0.6);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-lg);
  padding-bottom: var(--space-md);
}

.site-branding {
  display: flex;
  align-items: center;
  column-gap: var(--space-sm);
  text-decoration: none;
}

.logo-mark {
  width: 72px;
  height: 72px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background-color: rgba(183, 199, 160, 0.2); /* soft circle behind logo */
  border-radius: 50%;
  overflow: hidden;
}

.logo-image {
  width: 64px;
  height: auto;
  object-fit: contain;
}

.logo-text {
  display: flex;
  flex-direction: column;
  font-family: var(--font-body);
  color: var(--color-neutral-800);
}

.logo-name {
  font-size: 18px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.logo-subtitle {
  font-size: 12px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.primary-nav {
  font-family: var(--font-body);
}

.primary-nav-list {
  list-style: none;
  display: flex;
  align-items: center;
  column-gap: var(--space-lg);
  margin: 0;
  padding: 0;
}

.primary-nav-item a {
  font-size: 14px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.13em;
  text-transform: uppercase;
  color: var(--color-secondary-600);
  text-decoration: none;
  padding-bottom: 6px;
  border-bottom: 2px solid transparent;
  transition: color 0.2s ease, border-color 0.2s ease;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus {
  color: var(--color-neutral-800);
  border-color: var(--color-secondary-400);
}

/* Active page state (optional, set via aria-current or class) */

.primary-nav-item a[aria-current="page"],
.primary-nav-item a.is-active {
  color: var(--color-neutral-800);
  border-color: var(--color-primary-600);
  font-weight: var(--font-weight-medium);
}

/* Footer styling */

.site-footer {
  background-color: var(--color-neutral-000);
  border-top: 1px solid rgba(220, 228, 221, 0.8);
  color: var(--color-neutral-800);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-xl);
  padding-top: var(--space-xl);
  padding-bottom: var(--space-lg);
}

.footer-branding {
  flex: 1 1 260px;
}

.footer-logo {
  display: inline-flex;
  align-items: center;
  column-gap: var(--space-sm);
  margin-bottom: var(--space-sm);
  text-decoration: none;
}

.footer-logo-mark {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, rgba(183, 199, 160, 0.7), rgba(138, 168, 131, 0.4));
}

.footer-logo-text {
  font-family: var(--font-heading);
  font-size: 18px;
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-800);
}

.footer-tagline {
  max-width: 320px;
  font-size: 15px;
  line-height: var(--line-height-relaxed);
  color: rgba(75, 90, 82, 0.9);
}

.footer-links {
  flex: 2 1 360px;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-xl);
}

.footer-links-group {
  min-width: 160px;
}

.footer-heading {
  margin: 0 0 var(--space-xs);
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(75, 90, 82, 0.8);
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-nav-list li + li {
  margin-top: var(--space-xs);
}

.footer-nav-list a {
  font-size: 15px;
  font-weight: var(--font-weight-regular);
  color: var(--color-secondary-600);
  text-decoration: none;
}

.footer-nav-list a:hover,
.footer-nav-list a:focus {
  color: var(--color-neutral-800);
  text-decoration: underline;
}

.footer-bottom {
  background-color: var(--color-neutral-050);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  padding-top: var(--space-sm);
  padding-bottom: var(--space-sm);
}

.footer-meta {
  margin: 0;
  font-size: 13px;
  color: rgba(75, 90, 82, 0.75);
}

/* Optional hero section styles (for use on individual pages)
   This matches the nature-inspired banner visible in the design. */

.page-hero {
  position: relative;
  width: 100%;
  min-height: 220px;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  display: flex;
  align-items: center;
  justify-content: center;
}

.page-hero::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to bottom,
    rgba(0, 0, 0, 0.16),
    rgba(0, 0, 0, 0.25)
  );
}

.page-hero-heading {
  position: relative;
  z-index: 1;
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-000);
  text-align: center;
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    row-gap: var(--space-md);
  }

  .primary-nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-xs);
  }
}

@media (max-width: 720px) {
  .container {
    padding-left: var(--space-md);
    padding-right: var(--space-md);
  }

  .primary-nav-list {
    column-gap: var(--space-md);
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-links {
    flex-direction: column;
  }
}

@media (max-width: 480px) {
  .primary-nav-list {
    flex-direction: column;
    align-items: flex-start;
  }

  .logo-mark {
    width: 60px;
    height: 60px;
  }

  .page-hero {
    min-height: 180px;
  }
}
